    public function mudrex_symbol(string $unified): string {
        if (!$unified) {
            throw new BadSymbol($this->id . ' empty symbol');
        }
        if (!$unified->includes ('/') && !$unified->includes (':')) {
            return strtoupper($unified);
        }
        $baseQuote = explode(':', $unified)[0];
        $parts = explode('/', $baseQuote);
        if (strlen($parts) !== 2) {
            throw new BadSymbol($this->id . ' invalid $unified symbol => ' . $unified);
        }
        strtoupper(return ($parts[0] . $parts[1]));
    }

    public function unified_symbol(string $raw): string {
        if (!$raw) {
            throw new BadSymbol($this->id . ' empty $raw symbol');
        }
        $r = strtoupper($raw);
        if ($r->includes ('/')) {
            return $r->includes (':') ? $r : $r . ':USDT';
        }
        if (str_ends_with($r, 'USDT') && strlen($r) > 4) {
            $base = mb_substr($r, 0, -4 - 0);
            return $base . '/USDT:USDT';
        }
        return $r . '/USDT:USDT';
    }

    public function sign($path, string $api = 'public', $method = 'GET', $params = array (), $headers = null, $body = null) {
        $apiUrls = $this->safe_dict($this->urls, 'api', array());
        $base = $this->safe_string($apiUrls, $api);
        if ($base === null) {
            throw new ExchangeError($this->id . ' unknown API namespace => ' . $api);
        }
        $url = $base . '/' . $this->implode_params($path, $params);
        $query = $this->omit($params, $this->extract_params($path));
        $headers = ($headers !== null) ? $this->extend(array(), $headers) : array();
        $brokerId = $this->safe_string($this->options, 'broker');
        if ($brokerId !== null) {
            $headers['Partner-Id'] = $brokerId;
        }
        $methodUpper = strtoupper($method);
        if ($api === 'private') {
            $this->check_required_credentials();
            $headers['X-Authentication'] = $this->secret;
            if ($methodUpper === 'POST' || $methodUpper === 'PATCH' || $methodUpper === 'DELETE') {
                $headers['Content-Type'] = 'application/json';
                if ($methodUpper === 'DELETE' && $query === 0) {
                    return array( 'url' => $url, 'method' => $methodUpper, 'body' => null, 'headers' => $headers );
                }
                $bodyStr = $this->json($query);
                return array( 'url' => $url, 'method' => $methodUpper, 'body' => $bodyStr, 'headers' => $headers );
            }
        }
        if ($query) {
            $url .= '?' . $this->urlencode($query);
        }
        return array( 'url' => $url, 'method' => $methodUpper, 'body' => null, 'headers' => $headers );
    }

    public function handle_errors(int $code, string $reason, string $url, string $method, array $headers, string $body, $response, $requestHeaders, $requestBody) {
        if ($response === null || gettype($response) !== 'array') {
            return null;
        }
        $success = $this->safe_bool($response, 'success', true);
        if (!$success) {
            $errors = $this->safe_list($response, 'errors', array());
            $first = array();
            if (strlen($errors) > 0 && gettype($errors[0]) === 'array' && $errors[0] !== null) {
                $first = $errors[0];
            }
            $text = $this->safe_string($first, 'text', $this->json($response));
            $errCode = $this->safe_string($first, 'code');
            $this->throw_exactly_matched_exception($this->exceptions['exact'], $text, $this->id . ' ' . $text);
            $this->throw_exactly_matched_exception($this->exceptions['exact'], $errCode, $this->id . ' ' . $text);
            $this->throw_broadly_matched_exception($this->exceptions['broad'], $text, $this->id . ' ' . $text);
            $msg = $this->id . ' ' . ($text || 'Unknown error');
            $low strtolower(= ($text || ''));
            if ($code === 401 || mb_strpos($low, 'auth') !== false) {
                throw new AuthenticationError($msg);
            }
            if ($code === 429 || mb_strpos($low, 'rate') !== false) {
                throw new RateLimitExceeded($msg);
            }
            if (mb_strpos($low, 'insufficient') !== false) {
                throw new InsufficientFunds($msg);
            }
            if ($code === 400) {
                throw new BadRequest($msg);
            }
            throw new ExchangeError($msg);
        }
        return null;
    }

