    public function fetch_tickers(?array $symbols = null, $params = array ()): array {
        $this->load_markets();
        $request = array();
        $response = $this->request('futures', 'private', 'GET', $this->extend($request, $params));
        $data = $this->safe_value($response, 'data', array());
        $rows = (gettype($data) === 'array' && array_keys($data) === array_keys(array_keys($data))) ? $data : $this->safe_list($data, 'items', array());
        $resultTickers = array();
        for ($i = 0; $i < count($rows); $i++) {
            $t = $rows[$i];
            $sym = $this->safe_string($t, 'symbol');
            if ($sym === null) {
                continue;
            }
            $unified = $this->unified_symbol($sym);
            if ($symbols !== null && !$this->in_array($unified, $symbols)) {
                continue;
            }
            $m = $this->safe_value($this->markets, $unified);
            $resultTickers[$unified] = $this->parse_ticker($t, $m);
        }
        return $this->filter_by_array_tickers($resultTickers, 'symbol', $symbols);
    }

    public function parse_ticker(array $ticker, ?array $market = null): array {
