    public function fetch_balance($params = array ()): array {
        $this->load_markets();
        $tradeCurrency = $this->safe_string_2($params, 'trade_currency', 'tradeCurrency');
        $spotReq = array();
        $futReq = array();
        if ($tradeCurrency !== null) {
            $spotReq['currency'] = $tradeCurrency;
            $futReq['trade_currency'] = $tradeCurrency;
        } elseif ($params['currency'] !== null) {
            $spotReq['currency'] = $params['currency'];
            $futReq['trade_currency'] = $params['currency'];
        }
        $p1 = $this->omit($params, ['trade_currency', 'tradeCurrency', 'currency']);
        $spot = $this->request('wallet/funds', 'private', 'GET', $this->extend($spotReq, $p1));
        $fut = $this->request('futures/funds', 'private', 'GET', $this->extend($futReq, $p1));
        return $this->parse_balance(array( 'spot' => $spot, 'futures' => $fut, 'currency' => $spotReq['currency'] || 'USDT' ));
    }

    public function parse_balance(mixed $response): array {
        $spotR = $this->safe_dict($response, 'spot', array());
        $futR = $this->safe_dict($response, 'futures', array());
        $spotD = $this->safe_dict($spotR, 'data', array());
        $futD = $this->safe_dict($futR, 'data', array());
        $currency = $this->safe_string($response, 'currency', 'USDT');
        $futBal = $this->safe_number($futD, 'balance');
        $futLocked = $this->safe_number($futD, 'locked_amount');
        $futFree = null;
        if ($futBal !== null && $futLocked !== null) {
            $futFree = $futBal - $futLocked;
        }
        $spotWithdrawable = $this->safe_number($spotD, 'withdrawable');
        $timestamp = $this->milliseconds();
        $balance = array(
            'info' => array( $spotR, $futR ),
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
        );
        $balance[$currency] = array(
            'free' => $futFree,
            'used' => $futLocked,
            'total' => $futBal,
        );
        if ($spotWithdrawable !== null) {
            $balance['SPOT'] = array(
                'free' => $spotWithdrawable,
                'used' => 0,
                'total' => $this->safe_number($spotD, 'total'),
            );
        }
        return $this->safe_balance($balance);
    }

