    public function set_leverage(?int $leverage, ?string $symbol = null, $params = array ()): mixed {
        if ($symbol === null) {
            throw new ArgumentsRequired($this->id . ' setLeverage() requires a symbol');
        }
        $this->load_markets();
        $market = $this->market($symbol);
        $marginType = $this->safe_string($params, 'marginType', 'ISOLATED');
        $body = array(
            'margin_type' => $marginType,
            'leverage' => $leverage,
        );
        $tradeCurrency = $this->safe_string_2($params, 'trade_currency', 'tradeCurrency');
        if ($tradeCurrency !== null) {
            $body['trade_currency'] = $tradeCurrency;
        }
        $path = 'futures/' . $market['id'] . '/leverage?is_symbol=1';
        $response = $this->request($path, 'private', 'POST', $this->extend($body, $this->omit($params, ['trade_currency', 'tradeCurrency', 'marginType'])));
        $leverages = $this->safe_dict($this->options, 'leverages', array());
        $this->options['leverages'] = $this->extend($leverages, array( [$market['symbol']] => $leverage ));
        return $response;
    }

    public function create_order(string $symbol, string $type, string $side, float $amount, ?float $price = null, $params = array ()): array {
        $this->check_required_credentials();
        $this->load_markets();
        $market = $this->market($symbol);
        $ms = $market['id'];
        $lev = $this->safe_integer($params, 'leverage');
        $leverages = $this->safe_dict($this->options, 'leverages', array());
        if ($lev === null) {
            $lev = $this->safe_integer($leverages, $market['symbol']);
        }
        if ($lev === null) {
            throw new ArgumentsRequired($this->id . " createOrder() requires $params['leverage'] or a prior setLeverage() call");
        }
        $trig = ($type === 'market') ? 'MARKET' : 'LIMIT';
        $otype = ($side === 'buy') ? 'LONG' : 'SHORT';
        $px = $price;
        if ($type === 'market' && ($px === null || $px === 0)) {
            $t = $this->fetch_ticker($symbol);
            $px = $this->safe_number($t, 'last');
            if ($px === null) {
                throw new ExchangeError($this->id . ' could not resolve $market order $price from ticker');
            }
        }
        $body = array(
            'leverage' => (string) $lev,
            'quantity' => (string) $amount,
            'order_price' => (string) $px,
            'order_type' => $otype,
            'trigger_type' => $trig,
            'reduce_only' => $this->safe_bool($params, 'reduceOnly', false),
        );
        $tradeCurrency = $this->safe_string_2($params, 'trade_currency', 'tradeCurrency');
        if ($tradeCurrency !== null) {
            $body['trade_currency'] = $tradeCurrency;
        }
        if ($this->safe_bool($params, 'takeProfit', false) || $params['takeprofit_price'] !== null) {
            $body['is_takeprofit'] = true;
            $tp = $this->safe_string_2($params, 'takeprofit_price', 'takeProfitPrice');
            if ($tp !== null) {
                $body['takeprofit_price'] = $tp;
            }
        }
        if ($this->safe_bool($params, 'stopLoss', false) || $params['stoploss_price'] !== null) {
            $body['is_stoploss'] = true;
            $sl = $this->safe_string_2($params, 'stoploss_price', 'stopLossPrice');
            if ($sl !== null) {
                $body['stoploss_price'] = $sl;
            }
        }
        $path = 'futures/' . $ms . '/order?is_symbol=1';
        $response = $this->request($path, 'private', 'POST', $this->extend($body, $this->omit($params, ['leverage', 'reduceOnly', 'takeProfit', 'stopLoss', 'takeprofit_price', 'takeProfitPrice', 'stoploss_price', 'stopLossPrice', 'trade_currency', 'tradeCurrency'])));
        $leverages = $this->safe_dict($this->options, 'leverages', array());
        $this->options['leverages'] = $this->extend($leverages, array( [$market['symbol']] => $lev ));
        $data = $this->safe_dict($response, 'data', $response);
        return $this->parse_order($data, $market);
    }

    public function edit_order(string $id, string $symbol, string $type, string $side, ?float $amount = null, ?float $price = null, $params = array ()): array {
        $this->check_required_credentials();
        $this->load_markets();
        $market = null;
        if ($symbol !== null) {
            $market = $this->market($symbol);
        }
        $request = array(
            'order_id' => $id,
        );
        if ($amount !== null) {
            $request['quantity'] = (string) $amount;
        }
        if ($price !== null) {
            $request['order_price'] = (string) $price;
        }
        $tradeCurrency = $this->safe_string_2($params, 'trade_currency', 'tradeCurrency');
        if ($tradeCurrency !== null) {
            $request['trade_currency'] = $tradeCurrency;
        }
        $response = $this->request('futures/orders/' . $id, 'private', 'PATCH', $this->extend($request, $this->omit($params, ['trade_currency', 'tradeCurrency'])));
        $data = $this->safe_dict($response, 'data', $response);
        return $this->parse_order($data, $market);
    }

    public function parse_order(array $order, ?array $market = null): array {
        $market = $this->safe_market(null, $market);
        $oid = $this->safe_string_2($order, 'order_id', 'id');
        $rawSide = $this->safe_string_upper($order, 'order_type');
        $side = null;
        if ($rawSide === 'LONG') {
            $side = 'buy';
        } elseif ($rawSide === 'SHORT') {
            $side = 'sell';
        }
        $trig = $this->safe_string_upper($order, 'trigger_type');
        $typ = null;
        if ($trig === 'MARKET') {
            $typ = 'market';
        } elseif ($trig === 'LIMIT') {
            $typ = 'limit';
        }
        $ts = $this->parse8601($this->safe_string($order, 'created_at'));
        if ($ts === null) {
            $ts = $this->milliseconds();
        }
        $statusL = $this->safe_string_lower($order, 'status');
        $status = ($statusL === 'open' || $statusL === 'created' || $statusL === 'new') ? 'open' : $statusL;
        $sym = $this->safe_string($market, 'symbol');
        if (!$sym) {
            $oms = $this->safe_string($order, 'symbol');
            if ($oms !== null) {
                $sym = $this->unified_symbol($oms);
            }
        }
        return $this->safe_order(array(
            'info' => $order,
            'id' => $oid,
            'clientOrderId' => null,
            'timestamp' => $ts,
            'datetime' => $this->iso8601($ts),
            'lastTradeTimestamp' => null,
            'symbol' => $sym,
            'type' => $typ,
            'timeInForce' => null,
            'postOnly' => null,
            'side' => $side,
            'price' => $this->safe_number_2($order, 'price', 'order_price'),
            'stopPrice' => null,
            'triggerPrice' => null,
            'amount' => $this->safe_number_2($order, 'quantity', 'amount'),
            'cost' => null,
            'average' => null,
            'filled' => null,
            'remaining' => null,
            'status' => $status,
            'fee' => null,
            'trades' => array(),
            'fees' => array(),
            'lastUpdateTimestamp' => null,
            'reduceOnly' => $this->safe_bool($order, 'reduce_only'),
        ), $market);
    }

