    public function fetch_orders_by_state(string $state, ?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()): array {
        $this->load_markets();
        $q = array();
        if ($limit !== null) {
            $q['limit'] = $limit;
        }
        $tradeCurrency = $this->safe_string_2($params, 'trade_currency', 'tradeCurrency');
        if ($tradeCurrency !== null) {
            $q['trade_currency'] = $tradeCurrency;
        }
        $path = 'futures/orders';
        if ($state === 'closed') {
            $path = 'futures/orders/history';
        }
        $response = $this->request($path, 'private', 'GET', $this->extend($q, $this->omit($params, ['trade_currency', 'tradeCurrency'])));
        $data = $this->safe_value($response, 'data', array());
        $rows = $this->to_array($data);
        $market = null;
        if ($symbol !== null) {
            $market = $this->market($symbol);
        }
        $orders = array();
        for ($i = 0; $i < count($rows); $i++) {
            $orders[] = $this->parse_order($rows[$i], $market);
        }
        return $this->filter_by_symbol_since_limit($orders, $symbol, $since, $limit);
    }

    public function fetch_orders(?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()): array {
        return $this->fetch_orders_by_state('closed', $symbol, $since, $limit, $params);
    }

    public function fetch_open_orders(?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()): array {
        return $this->fetch_orders_by_state('open', $symbol, $since, $limit, $params);
    }

    public function fetch_closed_orders(?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()): array {
        return $this->fetch_orders_by_state('closed', $symbol, $since, $limit, $params);
    }

    public function fetch_positions(?array $symbols = null, $params = array ()): array {
        $this->load_markets();
        $q = array();
        $tradeCurrency = $this->safe_string_2($params, 'trade_currency', 'tradeCurrency');
        if ($tradeCurrency !== null) {
            $q['trade_currency'] = $tradeCurrency;
        }
        $response = $this->request('futures/positions', 'private', 'GET', $this->extend($q, $this->omit($params, ['trade_currency', 'tradeCurrency'])));
        $data = $this->safe_value($response, 'data', array());
        if ($data === null) {
            return array();
        }
        $rows = $this->to_array($data);
        $out => Positionarray() = array();
        for ($i = 0; $i < count($rows); $i++) {
            $p = $rows[$i];
            $symRaw = $this->safe_string($p, 'symbol');
            $m = null;
            if ($symRaw !== null) {
                $u = $this->unified_symbol($symRaw);
                $m = $this->resolveMarketOptional ($u);
            }
            $pos = $this->parse_position($p, $m);
            $out[] = $pos;
        }
        return $this->filter_by_array_positions($out, 'symbol', $symbols);
    }

    public function parse_position(array $position, ?array $market = null): array {
        $market = $this->safe_market(null, $market);
        $ms = $this->safe_string($position, 'symbol');
        $symbol = $this->safe_string($market, 'symbol') ?? ($ms ? $this->unified_symbol($ms) : null);
        $rawSide = $this->safe_string_upper($position, 'order_type');
        $side = null;
        if ($rawSide === 'LONG') {
            $side = 'long';
        } elseif ($rawSide === 'SHORT') {
            $side = 'short';
        }
        $ts = $this->parse8601($this->safe_string($position, 'updated_at'));
        if ($ts === null) {
            $ts = $this->parse8601($this->safe_string($position, 'created_at'));
        }
        return array(
            'info' => $position,
            'id' => $this->safe_string($position, 'id'),
            'symbol' => $symbol,
            'timestamp' => $ts,
            'datetime' => $this->iso8601($ts),
            'isolated' => true,
            'hedged' => null,
            'side' => $side,
            'contracts' => $this->safe_number($position, 'quantity'),
            'contractSize' => 1,
            'entryPrice' => $this->safe_number($position, 'entry_price'),
            'markPrice' => null,
            'notional' => null,
            'leverage' => $this->safe_integer($position, 'leverage'),
            'collateral' => null,
            'initialMargin' => null,
            'initialMarginPercentage' => null,
            'maintenanceMargin' => null,
            'maintenanceMarginPercentage' => null,
            'unrealizedPnl' => null,
            'liquidationPrice' => $this->safe_number($position, 'liquidation_price'),
            'marginMode' => 'isolated',
            'percentage' => null,
        );
    }

    public function close_position(string $symbol, ?string $side = null, $params = array ()): mixed {
        $this->check_required_credentials();
        $this->load_markets();
        $positionId = $this->safe_string($params, 'position_id');
        $amount = $this->safe_value($params, 'amount');
        if ($positionId === null) {
            $positions = $this->fetch_positions($symbol ? array( $symbol ) : null, $params);
            for ($i = 0; $i < count($positions); $i++) {
                $p = $positions[$i];
                if ($side !== null && $p['side'] !== $side) {
                    continue;
                }
                if ($p['symbol'] === $symbol || $this->mudrex_symbol($symbol) === $this->mudrex_symbol($p['symbol'])) {
                    $positionId = $this->safe_string($p, 'id');
                    break;
                }
            }
        }
        if ($positionId === null) {
            throw new OrderNotFound($this->id . ' closePosition() could not resolve position_id');
        }
        $request = array();
        $tradeCurrency = $this->safe_string_2($params, 'trade_currency', 'tradeCurrency');
        if ($tradeCurrency !== null) {
            $request['trade_currency'] = $tradeCurrency;
        }
        if ($amount !== null) {
            $partialPath = 'futures/positions/' . $positionId . '/close/partial';
            $orderType = $this->safe_string_upper($params, 'order_type', 'LIMIT');
            $body = $this->extend($request, array(
                'order_type' => $orderType,
                'quantity' => (string) $amount,
            ));
            $lp = $this->safe_string($params, 'limit_price');
            if ($orderType === 'LIMIT' && $lp !== null) {
                $body['limit_price'] = $lp;
            }
            return $this->request($partialPath, 'private', 'POST', $this->extend($body, $this->omit($params, ['trade_currency', 'tradeCurrency', 'order_type', 'limit_price', 'amount'])));
        }
        $closePath = 'futures/positions/' . $positionId . '/close';
        return $this->request($closePath, 'private', 'POST', $this->extend($request, $this->omit($params, ['trade_currency', 'tradeCurrency'])));
    }

    public function add_margin(string $symbol, float $amount, $params = array ()) {
        $this->load_markets();
        $positionId = $this->safe_string($params, 'position_id');
        if ($positionId === null) {
            $positions = $this->fetch_positions(array( $symbol ), $params);
            for ($i = 0; $i < count($positions); $i++) {
                $p = $positions[$i];
                if ($p['symbol'] === $symbol) {
                    $positionId = $this->safe_string($p, 'id');
                    break;
                }
            }
        }
        if ($positionId === null) {
            throw new OrderNotFound($this->id . ' addMargin() could not resolve position_id');
        }
        $request = array(
            'margin' => $amount->toString(),
        );
        $tradeCurrency = $this->safe_string_2($params, 'trade_currency', 'tradeCurrency');
        if ($tradeCurrency !== null) {
            $request['trade_currency'] = $tradeCurrency;
        }
        return $this->request('futures/positions/' . $positionId . '/add-margin', 'private', 'POST', $this->extend($request, $this->omit($params, ['trade_currency', 'tradeCurrency', 'position_id'])));
    }

    public function reduce_margin(string $symbol, float $amount, $params = array ()) {
        return $this->add_margin($symbol, -$amount, $params);
    }

