    public function parse_trade(array $trade, ?array $market = null): array {
        $market = $this->safe_market(null, $market);
        $ms = $this->safe_string($trade, 'symbol');
        $symbol = $this->safe_string($market, 'symbol') ?? ($ms ? $this->unified_symbol($ms) : null);
        $ts = $this->parse8601($this->safe_string($trade, 'created_at'));
        if ($ts === null) {
            $ts = $this->safe_integer($trade, 'time');
        }
        $side = $this->safe_string_lower($trade, 'side');
        $tradeSide = null;
        if ($side === 'buy' || $side === 'long') {
            $tradeSide = 'buy';
        } elseif ($side === 'sell' || $side === 'short') {
            $tradeSide = 'sell';
        }
        $fee = null;
        $feeCost = $this->safe_number($trade, 'fee_amount');
        if ($feeCost !== null) {
            $fee = array(
                'cost' => $feeCost,
                'currency' => $this->safe_string($trade, 'trade_currency'),
            );
        }
        return $this->safe_trade(array(
            'info' => $trade,
            'timestamp' => $ts,
            'datetime' => $this->iso8601($ts),
            'symbol' => $symbol,
            'id' => $this->safe_string_2($trade, 'execId', 'id'),
            'order' => $this->safe_string($trade, 'order_id'),
            'type' => $this->safe_string_lower($trade, 'trigger_type'),
            'side' => $tradeSide,
            'takerOrMaker' => null,
            'price' => $this->safe_number($trade, 'price'),
            'amount' => $this->safe_number_2($trade, 'size', 'quantity'),
            'cost' => null,
            'fee' => $fee,
        ), $market);
    }

    public function transfer(string $code, float $amount, string $fromAccount, string $toAccount, $params = array ()): array {
        $mp = array(
            'spot' => 'SPOT',
            'SPOT' => 'SPOT',
            'futures' => 'FUTURES',
            'future' => 'FUTURES',
            'FUTURES' => 'FUTURES',
        );
        $fw = $this->safe_string($mp, $fromAccount, strtoupper($fromAccount));
        $tw = $this->safe_string($mp, $toAccount, strtoupper($toAccount));
        $body = array(
            'from_wallet_type' => $fw,
            'to_wallet_type' => $tw,
            'amount' => (string) $amount,
        );
        $path = 'wallet/futures/transfer';
        if ($code === 'INR') {
            $path = 'futures/transfers/inr';
        } else {
            // default USDT does not use the inr $path
            $tradeCurrency = $this->safe_string_2($params, 'trade_currency', 'tradeCurrency');
            if ($tradeCurrency === 'INR') {
                $path = 'futures/transfers/inr';
            }
        }
        $response = $this->request($path, 'private', 'POST', $body, null, null, array( 'cost' => 5 ));
        $data = $this->safe_dict($response, 'data', $response);
        return array(
            'info' => $response,
            'id' => $this->safe_string($data, 'id'),
            'timestamp' => null,
            'datetime' => null,
            'currency' => $code,
            'amount' => $amount,
            'fromAccount' => $fw,
            'toAccount' => $tw,
            'status' => 'ok',
        );
    }
}
